  "ui.staff.restoreTeam": { en: "Restore default team", nl: "Standaardteam herstellen", de: "Standardteam wiederherstellen", fr: "Restaurer l'équipe par défaut", es: "Restaurar equipo por defecto" },
  "ui.staff.fullName": { en: "Full name", nl: "Volledige naam", de: "Vollständiger Name", fr: "Nom complet", es: "Nombre completo" },
  "ui.staff.fullNamePh": { en: "e.g. Sanne de Boer", nl: "bijv. Sanne de Boer", de: "z. B. Sanne de Boer", fr: "par ex. Sanne de Boer", es: "p. ej. Sanne de Boer" },
  "ui.staff.role": { en: "Role", nl: "Rol", de: "Rolle", fr: "Rôle", es: "Rol" },
