  "ui.staff.worksOn": { en: "Works on", nl: "Werkt op", de: "Arbeitet an", fr: "Travaille le", es: "Trabaja los" },
  "ui.staff.addResource": { en: "Add resource", nl: "Resource toevoegen", de: "Ressource hinzufügen", fr: "Ajouter une ressource", es: "Añadir recurso" },
  "ui.staff.noShiftPlan": { en: "No shift plan", nl: "Geen dienstenplan", de: "Kein Schichtplan", fr: "Aucun plan d'équipe", es: "Sin plan de turnos" },
  "ui.staff.applyPlan": { en: "Apply plan", nl: "Plan toepassen", de: "Plan anwenden", fr: "Appliquer le plan", es: "Aplicar plan" },
  "ui.staff.searchEmployee": { en: "Search employee…", nl: "Zoek medewerker…", de: "Mitarbeiter suchen…", fr: "Rechercher un employé…", es: "Buscar empleado…" },
  "ui.leave.title": { en: "Leave & absences ({n})", nl: "Verlof & afwezigheden ({n})", de: "Urlaub & Abwesenheiten ({n})", fr: "Congés et absences ({n})", es: "Ausencias y bajas ({n})" },
  "ui.leave.onRoster": { en: "On roster", nl: "Op rooster", de: "Im Dienstplan", fr: "Sur le planning", es: "En el cuadrante" },
  "ui.leave.none": { en: "No leave or absences yet.", nl: "Nog geen verlof of afwezigheden.", de: "Noch kein Urlaub oder Abwesenheiten.", fr: "Aucun congé ni absence pour le moment.", es: "Todavía no hay ausencias ni bajas." },
  "ui.house.assignAnimal": { en: "Assign animal (from registry)", nl: "Dier toewijzen (uit register)", de: "Tier zuweisen (aus Register)", fr: "Affecter un animal (depuis le registre)", es: "Asignar animal (desde el registro)" },
  "ui.house.assignNone": { en: "— none / type below —", nl: "— geen / typ hieronder —", de: "— keines / unten eingeben —", fr: "— aucun / saisir ci-dessous —", es: "— ninguno / escriba abajo —" },
